mapper.select:
SELECT id, registration_id, patient_id, patient_name, doctor_name, department_name, visit_type, chief_complaint, diagnosis, doctor_advice, vital_signs, medical_record, prescription, check_items, status, created_at, updated_at, deleted FROM clinic_consultation WHERE deleted = 0
AND (patient_name LIKE CONCAT('%', #{keyword}, '%') OR doctor_name LIKE CONCAT('%', #{keyword}, '%') OR diagnosis LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY id DESC LIMIT #{size} OFFSET #{offset}

mapper.update:
UPDATE clinic_consultation
SET deleted = 1, updated_at = NOW()
WHERE id = #{id}
